import React from "react";

const Assessment = () => {
  return (
    <>
      <div className="container">
        <div className="section-container">
          <h1>Get Your Free Cloud Cost Assesment</h1>
          <p>
            Your cloud is costing too much. Let's fix it. Discover how to reduce spending by 20 -
            30%.
          </p>
          <div>
            <section>
                <p>What You''ll Get:</p>
                <li>Detailed spend breakdown by service & team</li>
                <li>Projected savings estimate</li>
                
            </section>
          </div>
        </div>
      </div>
    </>
  );
};

export default Assessment;
